```c
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int a, b;
    scanf("%d %d", &a, &b);
    int g = gcd(a, b);
    a /= g;
    b /= g;
    if (abs(a - b) <= 1) {
        printf("Equal\n");
    } else if (a < b) {
        printf("Dasha\n");
    } else {
        printf("Masha\n");
    }
    return 0;
}
```

